```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Linq.Expressions;
using System.Threading.Tasks;

public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;

    public BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync()
    {
        return await _context.Set<T>().ToListAsync();
    }

    public virtual async Task<T> GetByIdAsync(object id)
    {
        return await _context.Set<T>().FindAsync(id);
    }

    public virtual async Task<T> GetByDynamicAsync(Dictionary<string, object> filter)
    {
        var entitySet = _context.Set<T>();

        var parameter = Expression.Parameter(typeof(T), "e");

        var predicate = Expression.Lambda<Func<T, bool>>(
            GetDynamicExpression(parameter, filter),
            parameter
        );

        return await entitySet.Where(predicate).FirstOrDefaultAsync();
    }

    private Expression GetDynamicExpression(ParameterExpression parameter, Dictionary<string, object> filter)

